#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <fcntl.h>
#include <errno.h>

#define MAX_PATH 1024
#define MAX_HASH 64
#define MAX_MSG 256
#define MAX_FILES 1024

typedef struct {
    char path[MAX_PATH];
    char hash[MAX_HASH];
} FileEntry;

typedef struct {
    char hash[MAX_HASH];
    char msg[MAX_MSG];
    time_t timestamp;
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

char* read_file(const char* path, size_t* size) {
    FILE* f = fopen(path, "rb");
    if (!f) return NULL;
    fseek(f, 0, SEEK_END);
    *size = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* buf = malloc(*size + 1);
    fread(buf, 1, *size, f);
    buf[*size] = '\0';
    fclose(f);
    return buf;
}

void write_file(const char* path, const char* data, size_t size) {
    FILE* f = fopen(path, "wb");
    fwrite(data, 1, size, f);
    fclose(f);
}

void sha1(const char* data, size_t len, char* out) {
    // dummy hash for simplicity
    static int counter = 0;
    sprintf(out, "%d", counter++);
}

void init_repo() {
    mkdir(".git", 0755);
    mkdir(".git/objects", 0755);
    mkdir(".git/refs", 0755);
    FILE* f = fopen(".git/HEAD", "w");
    fclose(f);
    printf("Initialized empty minigit repository\n");
}

void add_file(const char* path) {
    size_t size;
    char* data = read_file(path, &size);
    if (!data) {
        fprintf(stderr, "error: could not read %s\n", path);
        exit(1);
    }
    char hash[MAX_HASH];
    sha1(data, size, hash);
    char obj_path[MAX_PATH];
    sprintf(obj_path, ".git/objects/%s", hash);
    write_file(obj_path, data, size);
    free(data);

    // update index
    FILE* index = fopen(".git/index", "a");
    fprintf(index, "%s %s\n", path, hash);
    fclose(index);
}

void load_index(FileEntry* files, int* count) {
    *count = 0;
    FILE* index = fopen(".git/index", "r");
    if (!index) return;
    while (fscanf(index, "%s %s\n", files[*count].path, files[*count].hash) == 2) {
        (*count)++;
    }
    fclose(index);
}

void save_commit(Commit* c) {
    char path[MAX_PATH];
    sprintf(path, ".git/objects/%s", c->hash);
    FILE* f = fopen(path, "w");
    fprintf(f, "%s\n%s\n%ld\n%d\n", c->hash, c->msg, c->timestamp, c->file_count);
    for (int i = 0; i < c->file_count; i++) {
        fprintf(f, "%s %s\n", c->files[i].path, c->files[i].hash);
    }
    fclose(f);
}

const char* commit(const char* msg) {
    static Commit c;
    strcpy(c.msg, msg);
    c.timestamp = time(NULL);
    sha1(msg, strlen(msg), c.hash);
    load_index(c.files, &c.file_count);
    save_commit(&c);

    FILE* head = fopen(".git/HEAD", "w");
    fprintf(head, "%s\n", c.hash);
    fclose(head);

    // clear index
    fclose(fopen(".git/index", "w"));

    return c.hash;
}

void checkout_commit(const char* hash) {
    char path[MAX_PATH];
    sprintf(path, ".git/objects/%s", hash);
    FILE* f = fopen(path, "r");
    if (!f) {
        fprintf(stderr, "error: unknown commit %s\n", hash);
        exit(1);
    }
    Commit c;
    fscanf(f, "%s\n%[^\n]\n%ld\n%d\n", c.hash, c.msg, &c.timestamp, &c.file_count);
    for (int i = 0; i < c.file_count; i++) {
        fscanf(f, "%s %s\n", c.files[i].path, c.files[i].hash);
    }
    fclose(f);

    // checkout files
    for (int i = 0; i < c.file_count; i++) {
        char obj_path[MAX_PATH];
        sprintf(obj_path, ".git/objects/%s", c.files[i].hash);
        size_t size;
        char* data = read_file(obj_path, &size);
        write_file(c.files[i].path, data, size);
        free(data);
    }

    // update HEAD
    FILE* head = fopen(".git/HEAD", "w");
    fprintf(head, "%s\n", hash);
    fclose(head);
}

void reset_commit(const char* hash) {
    checkout_commit(hash);
}

int main(int argc, char** argv) {
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command> [args]\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit add <file>\n");
            return 1;
        }
        add_file(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) {
            fprintf(stderr, "save\n");
            return 1;
        }
        const char* hash = commit(argv[2]);
        printf("%s\n", hash);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "usage: minigit checkout <hash>\n");
            return 1;
        }
        checkout_commit(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            fprintf(stderr), "usage: minigit reset <hash>\n");
            return 1;
        }
        reset_commit(argv[2]);
    } else {
        fprintf(stderr, "unknown command: %s\n", argv[1]);
        return 1;
    }
    return 0;
}
